import { Component, OnInit, HostListener } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { FormControl } from '@angular/forms';
import { debounceTime, distinctUntilChanged, switchMap } from 'rxjs/operators';
import { CartService } from '../services/cart.service';
import { AuthService } from '../services/auth.service';
import { ToastService } from '../services/toast.service';
import { Product } from '../models/models';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css']
})
export class HomeComponent implements OnInit {
  products: Product[] = [];
  filteredProducts: Product[] = [];
  searchResults: Product[] = [];
  loading = true;
  error = '';
  categories = ['All', 'Electronics', 'Fashion', 'Home', 'Books'];
  selectedCategory = 'All';
  searchQuery = '';
  searchControl = new FormControl('');
  showDropdown = false;
  activeSearchIndex = -1;
  highlightedProductId: number | null = null;
  zoomedProductId: number | null = null;

  constructor(
    private http: HttpClient,
    private cartService: CartService,
    private authService: AuthService,
    private toastService: ToastService,
    private router: Router
  ) {}

  ngOnInit() {
    this.loadProducts();
    this.setupSearch();
  }

  loadProducts() {
    this.loading = true;
    this.http.get<Product[]>('http://localhost:3000/api/products')
      .subscribe({
        next: (data) => {
          this.products = data;
          this.applyFilters();
          this.loading = false;
        },
        error: (error) => {
          this.error = 'Failed to load products';
          this.loading = false;
          this.toastService.showError('Failed to load products');
          console.error('Error loading products:', error);
        }
      });
  }

  setupSearch() {
    this.searchControl.valueChanges.pipe(
      debounceTime(300),
      distinctUntilChanged()
    ).subscribe(query => {
      this.searchQuery = query || '';
      if (this.searchQuery.length > 1) {
        this.performSearch(this.searchQuery);
        this.showDropdown = true;
      } else {
        this.searchResults = [];
        this.showDropdown = false;
        this.applyFilters();
      }
    });
  }

  performSearch(query: string) {
    const searchTerm = query.toLowerCase();
    this.searchResults = this.products.filter(product => 
      product.name.toLowerCase().includes(searchTerm) ||
      product.description.toLowerCase().includes(searchTerm) ||
      product.category.toLowerCase().includes(searchTerm)
    ).slice(0, 5); // Limit to 5 results
  }

  selectSearchResult(product: Product) {
    this.searchQuery = product.name;
    this.searchControl.setValue(product.name);
    this.showDropdown = false;
    this.highlightedProductId = product.id;
    this.applyFilters();
    
    // Scroll to the product
    setTimeout(() => {
      const element = document.getElementById(`product-${product.id}`);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth', block: 'center' });
        // Add highlight effect
        element.classList.add('highlight-pulse');
        setTimeout(() => {
          element.classList.remove('highlight-pulse');
        }, 2000);
      }
    }, 100);
  }

  @HostListener('document:click')
  onDocumentClick() {
    this.showDropdown = false;
  }

  onSearchInputClick(event: Event) {
    event.stopPropagation();
    if (this.searchQuery.length > 1) {
      this.showDropdown = true;
    }
  }

  onSearchKeyDown(event: KeyboardEvent) {
    if (event.key === 'ArrowDown') {
      event.preventDefault();
      this.activeSearchIndex = Math.min(this.activeSearchIndex + 1, this.searchResults.length - 1);
    } else if (event.key === 'ArrowUp') {
      event.preventDefault();
      this.activeSearchIndex = Math.max(this.activeSearchIndex - 1, -1);
    } else if (event.key === 'Enter') {
      if (this.activeSearchIndex >= 0 && this.searchResults[this.activeSearchIndex]) {
        this.selectSearchResult(this.searchResults[this.activeSearchIndex]);
      } else {
        this.onSearch();
      }
    } else if (event.key === 'Escape') {
      this.showDropdown = false;
    }
  }

  onSearch() {
    if (this.searchQuery && this.searchQuery.trim()) {
      this.showDropdown = false;
      this.applyFilters();
      
      // Find first matching product and highlight it
      const matchingProduct = this.filteredProducts[0];
      if (matchingProduct) {
        this.highlightedProductId = matchingProduct.id;
        setTimeout(() => {
          const element = document.getElementById(`product-${matchingProduct.id}`);
          if (element) {
            element.scrollIntoView({ behavior: 'smooth', block: 'center' });
            element.classList.add('highlight-pulse');
            setTimeout(() => {
              element.classList.remove('highlight-pulse');
            }, 2000);
          }
        }, 100);
      }
    }
  }

  clearSearch() {
    this.searchQuery = '';
    this.searchControl.setValue('');
    this.searchResults = [];
    this.showDropdown = false;
    this.highlightedProductId = null;
    this.applyFilters();
  }

  applyFilters() {
    let filtered = this.products;
    
    // Apply category filter
    if (this.selectedCategory !== 'All') {
      filtered = filtered.filter(p => p.category === this.selectedCategory);
    }
    
    // Apply search filter
    if (this.searchQuery) {
      const query = this.searchQuery.toLowerCase();
      filtered = filtered.filter(p => 
        p.name.toLowerCase().includes(query) || 
        p.description.toLowerCase().includes(query) ||
        p.category.toLowerCase().includes(query)
      );
    }
    
    this.filteredProducts = filtered;
  }

  onCategoryChange(category: string) {
    this.selectedCategory = category;
    this.applyFilters();
  }

  addToCart(product: Product) {
    if (!this.authService.isLoggedIn()) {
      this.toastService.showError('Please login to add items to cart');
      this.router.navigate(['/login']);
      return;
    }

    this.cartService.addToCart(product.id, 1).subscribe({
      next: () => {
        this.cartService.getCartCount();
        this.toastService.showSuccess(`${product.name} added to cart successfully!`);
        
        // Remove highlight after adding to cart
        this.highlightedProductId = null;
      },
      error: (error) => {
        this.toastService.showError(error.error?.error || 'Failed to add to cart');
      }
    });
  }

  shopNow() {
    // Scroll to products section
    document.getElementById('products-section')?.scrollIntoView({ behavior: 'smooth' });
  }

  getCategoryIcon(category: string): string {
    const icons: {[key: string]: string} = {
      'Electronics': 'fas fa-laptop',
      'Fashion': 'fas fa-tshirt',
      'Home': 'fas fa-home',
      'Books': 'fas fa-book'
    };
    return icons[category] || 'fas fa-tag';
  }

  // Mouse enter for zoom effect
  onProductMouseEnter(productId: number) {
    this.zoomedProductId = productId;
  }

  onProductMouseLeave() {
    this.zoomedProductId = null;
  }

  // Check if product should be highlighted
  isProductHighlighted(productId: number): boolean {
    return this.highlightedProductId === productId;
  }

  // Check if product should be zoomed
  isProductZoomed(productId: number): boolean {
    return this.zoomedProductId === productId;
  }
}
